class Logger{constructor(){this.enableDebugLog=!1,this._alreadyWarned={}}warn(e){return console&&(console.warn?console.warn(e):console.log&&console.log(e)),this}warnOnce(e){return this._alreadyWarned[e]||(this._alreadyWarned[e]=!0,logger.warn(e)),this}debug(e){return this.enableDebugLog&&console&&(console.debug?console.debug(e):console.log&&console.log(e)),this}}const logger=new Logger;export{Logger,logger};